// reactapp/src/components/AppointmentList.js
import React, { useEffect, useState } from "react";
import * as api from "../utils/api";

export default function AppointmentList() {
  const [loading, setLoading] = useState(true);
  const [appointments, setAppointments] = useState([]);
  const [error, setError] = useState("");

  useEffect(() => {
    let mounted = true;
    (async () => {
      setLoading(true);
      setError("");
      try {
        const u = JSON.parse(localStorage.getItem("user") || "null");
        if (!u) {
          setError("Not logged in");
          return;
        }

        if (u.role === "DOCTOR") {
          const doctors = await api.fetchDoctors();
          const doc = doctors.find((d) => String(d.userId) === String(u.id) || String(d.id) === String(u.id));
          if (!doc) {
            setError("No doctor profile found for this account.");
            return;
          }
          const appts = await api.fetchAppointmentsByDoctor(doc.id);
          if (!mounted) return;
          setAppointments(appts || []);
          return;
        }

        // USER flow: map logged-in username -> Patient record
        const patients = await api.fetchPatients();
        const username = (u.username || "").toLowerCase();
        const match = (patients || []).find((p) => {
          if (!p) return false;
          const patientName = (p.name || "").toLowerCase();
          const patientUsername = (p.username || "").toLowerCase();
          return username && (patientName === username || patientUsername === username);
        });

        if (!match) {
          setError("No patient record found for this account. Book an appointment to create one.");
          return;
        }

        const appts = await api.fetchAppointmentsByPatient(match.id);
        if (!mounted) return;
        setAppointments(appts || []);
      } catch (err) {
        console.error(err);
        setError(err?.message || "Failed to load appointments");
      } finally {
        if (mounted) setLoading(false);
      }
    })();

    return () => { mounted = false; };
  }, []);

  if (loading) return <div>Loading appointments…</div>;
  if (error) return <div style={{ color: "#b00020" }}>{error}</div>;
  if (!appointments || appointments.length === 0) return <div>No appointments found.</div>;

  return (
    <div style={{ maxWidth: 900, margin: "0 auto" }}>
      <h3>Your Appointments</h3>
      {appointments.map((a) => (
        <div key={a.id} style={{ border: "1px solid #ddd", padding: 12, marginBottom: 8 }}>
          <div><strong>Doctor:</strong> {a.doctor?.name || a.doctorName || a.doctorId || "—"}</div>
          <div><strong>When:</strong> {formatAppointmentTime(a)}</div>
          <div><strong>Reason:</strong> {a.reason}</div>
          <div><strong>Status:</strong> {String(a.status)}</div>
        </div>
      ))}
    </div>
  );
}

function formatAppointmentTime(a) {
  if (!a) return "";
  if (a.appointmentDate && a.appointmentTime) return `${a.appointmentDate} ${a.appointmentTime}`;
  if (a.createdAt) {
    try {
      const dt = new Date(a.createdAt);
      if (!isNaN(dt)) return dt.toLocaleString();
    } catch {}
  }
  if (a.appointmentTime) {
    try {
      const dt = new Date(a.appointmentTime);
      if (!isNaN(dt)) return dt.toLocaleString();
    } catch {}
  }
  return "Unknown time";
}
